# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System;
using UnityEngine;

public class Player : MonoBehaviour {
    public float health = 100f;
    public int currency = 100;
    private Action onDie;
    
    public void TakeDamage(float damage) {
        if (health > 0 && damage > 0) {
            health -= damage;
            if (health <= 0) {
                Die();
            }
        }
    }

    private void Die() {
        onDie?.Invoke();
        // handle death animation and effects here
    }

    public bool BuyItem(int itemPrice, Action onSuccess) {
        if (currency >= itemPrice) {
            currency -= itemPrice;
            onSuccess?.Invoke();
            return true;
        }
        return false;
    }
}